import jwt
from datetime import datetime, timedelta

# Define the secret key for signing the JWT
SECRET_KEY = 'your-secret-key'

def generate_jwt(user_id, role):
    # Set the payload to contain user id and role 
    payload = {
        'exp': datetime.utcnow() + timedelta(days=0, minutes=30), # Token will expire after 30 minutes
        'iat': datetime.utcnow(),
        'sub': str(user_id),   # subject of token (unique identifier)
        'role': role            # user's role
    }
    
    return jwt.encode(payload, SECRET_KEY, algorithm='HS256')